            name = row['Name']
            ordinal = version_info.get('Ordinal', 0)
            if name not in packages_by_name or ordinal > packages_by_name[name]['Ordinal']:
                packages_by_name[name] = {
                    'Name': name,
                    'Version': row['Version'],
                    'Ordinal': ordinal
                }
    except:
        continue

latest_releases = list(packages_by_name.values())

print('__RESULT__:')
print(json.dumps({
    'count': len(latest_releases),
    'releases': latest_releases
}))"}

