# Read the data
with open(file_path, 'r') as f:
    package_data = json.load(f)

# Process to find latest release versions for each package
packages_by_name = {}
for row in package_data:
    try:
        version_info = json.loads(row['VersionInfo'])
        if version_info.get('IsRelease', False):
            name = row['Name']
            ordinal = version_info.get('Ordinal', 0)
            if name not in packages_by_name or ordinal > packages_by_name[name]['Ordinal']:
                packages_by_name[name] = {
                    'Name': name,
                    'Version': row['Version'],
                    'Ordinal': ordinal
                }
    except:
        continue

latest_packages = list(packages_by_name.values())

# Output in required format
print('__RESULT__:')
result = {
    'total_latest_releases': len(latest_packages),
    'sample': latest_packages[:3]
}
print(json.dumps(result))"}

