    package_data = json.load(f)

# Process VersionInfo to find latest release for each package
packages_by_name = {}

for row in package_data:
    name = row['Name']
    version = row['Version']

    # Parse VersionInfo
    try:
        version_info = json.loads(row['VersionInfo'])
        is_release = version_info.get('IsRelease', False)
        ordinal = version_info.get('Ordinal', 0)

        # Only consider release versions
        if is_release:
            # Keep the version with highest ordinal for each package
            if name not in packages_by_name or ordinal > packages_by_name[name]['ordinal']:
                packages_by_name[name] = {
                    'Name': name,
                    'Version': version,
                    'Ordinal': ordinal
                }
    except:
        continue

latest_packages = list(packages_by_name.values())
print('__RESULT__:')
print(json.dumps({
    'total_packages': len(latest_packages),
    'sample': latest_packages[:3]
}))"}

